// Cholesky factorization: A is SPD, produces lower-triangular L
for (int r = 0; r < n; r++) {
    double s = A[r][r];
    for (int k = 0; k < r; k++) s -= L[r][k] * L[r][k];
    L[r][r] = sqrt(s);                                  // diagonal pivot
    for (int i = r + 1; i < n; i++) {
        double t = A[i][r];
        for (int k = 0; k < r; k++) t -= L[i][k] * L[r][k];
        L[i][r] = t / L[r][r];                          // sub-diagonal
    }
}

for r = 1, ..., n-1:
    for i = r+1, ..., n:
        f = -a_ir / a_rr;           // negative multiplier
        // E_i := E_i + f * E_r
        for j = r+1, ..., n:
            a_ij = a_ij + f * a_rj;
        a_ir = 0;
        b_i  = b_i + f * b_r;
